SELECT at_Icube_Archive.仮基本工事コード, at_Icube_Archive.仮基本工事略名, at_Genka_Edaban.基本工事コード, at_Genka_Edaban.基本工事名, at_Genka_Edaban.工事コード, at_Genka_Edaban.工事名, at_Genka_Edaban.枝番工事コード, at_Genka_Edaban.追加工事名称, at_Genka_Edaban.担当者名, at_Genka_Edaban.状況, at_Genka_Edaban.登録年月, at_Genka_Edaban.工事価格, at_Genka_Edaban.[工事原価(経費込)], at_Genka_Edaban.予定利益, at_Genka_Edaban.粗利率, at_Genka_Edaban.直接工事費, at_Genka_Edaban.経費, at_Genka_Edaban.作業所経費, at_Genka_Edaban.率, at_Genka_Edaban.設計料・他, at_Genka_Edaban.共通経費, at_Genka_Edaban.率2, at_Genka_Edaban.着工, at_Genka_Edaban.完成, at_Genka_Edaban.既払高：総額, at_Genka_Edaban.今後支払予定, at_Genka_Edaban.当月より前の支払金額, at_Genka_Edaban.当月支払金額, at_Genka_Edaban.当月以降予定金額, at_Genka_Edaban.行分類, at_Genka_Edaban.枝番工事コードerr, at_Genka_Edaban.枝番工事コードエラーチェック
FROM at_Icube_Archive INNER JOIN at_Genka_Edaban ON at_Icube_Archive.枝番工事コード = at_Genka_Edaban.枝番工事コード;
